import React, { useState } from 'react';
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";

export default function App() {
  const [todos, setTodos] = useState([
    { id: 1, text: "Write a new blog post.", completed: false },
    { id: 2, text: "Pick up laundry.", completed: false },
    { id: 3, text: "Die.", completed: false }
  ]);
  const [inputValue, setInputValue] = useState("");

  const handleAddTodo = () => {
    if (inputValue.trim() !== "") {
      const newTodo = {
        id: Date.now(),
        text: inputValue,
        completed: false
      };
      setTodos([...todos, newTodo]);
      setInputValue("");
    }
  };

  const toggleTodo = (id) => {
    setTodos(todos.map(todo => 
      todo.id === id ? { ...todo, completed: !todo.completed } : todo
    ));
  };

  return (
    <div className="min-h-screen bg-[#1a1a3a] flex justify-center font-sans">
      {/* Central Light Gray Container */}
      <div className="bg-[#efefef] w-full max-w-[600px] flex flex-col items-center pt-8 px-10">

        {/* Header Section */}
        <div className="bg-white border border-black px-12 py-2 mb-8 shadow-sm">
          <h1 className="text-[42px] font-normal text-[#333]">
            Another ToDo App
          </h1>
        </div>

        {/* Input Section */}
        <div className="w-full flex gap-2 mb-6">
          <Input 
            type="text" 
            placeholder="Add a ToDo" 
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            className="flex-grow bg-white border-[#ccc] rounded-none h-10 text-base placeholder:text-gray-400 focus-visible:ring-0 focus-visible:ring-offset-0"
            onKeyPress={(e) => e.key === 'Enter' && handleAddTodo()}
          />
          <Button 
            onClick={handleAddTodo}
            className="bg-[#007bff] hover:bg-[#0069d9] text-white px-10 h-10 rounded-[4px] text-base font-normal shadow-none"
          >
            Add
          </Button>
        </div>

        {/* ToDo List Section */}
        <div className="w-full space-y-3">
          {todos.map((todo) => (
            <div 
              key={todo.id} 
              className="bg-white border border-[#d8d8d8] p-[18px] flex items-center gap-3 shadow-sm"
            >
              <Checkbox 
                id={`todo-${todo.id}`}
                checked={todo.completed}
                onCheckedChange={() => toggleTodo(todo.id)}
                className="w-4 h-4 rounded-none border-gray-400 data-[state=checked]:bg-[#007bff] data-[state=checked]:border-[#007bff]"
              />
              <label 
                htmlFor={`todo-${todo.id}`}
                className={`text-[17px] text-[#333] cursor-pointer ${todo.completed ? 'line-through text-gray-400' : ''}`}
              >
                {todo.text}
              </label>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
}
